          </div>
          <div className="w-px" style={{ background: 'var(--aw-border)' }} />
          <div className="cursor-pointer hover:opacity-80 transition-opacity px-2 py-1 rounded-lg" onClick={() => openModal('شرکت‌ها', <CompanyListContent />)}>
