  };

  return (
    <div className="md:hidden flex flex-col items-center relative" style={{ zIndex: 30 }} data-chat-top-anchor>
      <EuAvatar
        palette="cyan"
        portrait={portraitSrc}
        name={displayName}
        cornerSlot={<AgentSelector />}
        swipeCount={group.length}
