                              className="w-6 h-6 rounded-md border-none bg-transparent text-[var(--aw-text-muted)] text-[11px] cursor-pointer flex items-center justify-center hover:text-[var(--aw-primary)] hover:bg-[var(--aw-primary-bg)]"
