      { id: 1, from: 'user',  body: 'در گزارش هفتگی نمودار خط نمایش داده نمی‌شود.', date: '۶ روز پیش' },
      { id: 2, from: 'agent', body: 'با به‌روزرسانی نسخه ۲.۳ این مشکل برطرف شد. ممنون از گزارش شما.', date: '۵ روز پیش' },
