    }</tbody></table>`;
    printPDF('گزارش Neura', `<h1>گزارش تجمیعی · بازه ${RANGE_OPTIONS.find(r => r.id === range)!.label} · دوره ${PERIOD_OPTIONS.find(p => p.id === period)!.label}</h1>${summary}${wTable}${lTable}`);
