                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </StateGate>
        </div>
      )}
      <PrimaryCTA label="افزودن لید جدید" icon="fa-solid fa-user-plus" onClick={addLead} />
    </div>
  );
}

