            { title: 'تبلیغ ساعت طلایی ۱۹–۲۱', impact: '+۱۵٪', desc: 'افزایش بودجه دیجیتال در پیک شام', icon: 'fa-solid fa-bullhorn', color: '#3B82F6' },
