        await delay(); const arr = load<CalendarEvent[]>('calendar', sc, () => calendarSeed(sc));
        const i = arr.findIndex(e => e.id === id); arr[i] = { ...arr[i], ...patch }; save('calendar', sc, arr); return arr[i];
      },
      async remove(id) {
        await delay(); const arr = load<CalendarEvent[]>('calendar', sc, () => calendarSeed(sc));
        save('calendar', sc, arr.filter(e => e.id !== id));
      },
